import java.io.*;import java.util.*;
public class Main{
  public static void main(String[] args)throws Exception{
    FastScanner fs=new FastScanner(System.in);
    int n=fs.nextInt();
    long best=Long.MIN_VALUE, cur=0;
    for(int i=0;i<n;i++){ long x=fs.nextLong(); cur=Math.max(x, cur+x); best=Math.max(best, cur);} 
    System.out.println(best);
  }
  static class FastScanner{
    private final InputStream in; private final byte[] buffer=new byte[1<<16]; private int ptr=0, len=0;
    FastScanner(InputStream is){in=is;}
    private int read()throws IOException{ if(ptr>=len){ len=in.read(buffer); ptr=0; if(len<=0) return -1;} return buffer[ptr++];}
    long nextLong()throws IOException{ long s=1, x=0; int c; do{ c=read(); }while(c<=32); if(c=='-'){ s=-1; c=read();}
      while(c>32){ x=x*10 + (c-'0'); c=read(); } return x*s; }
    int nextInt()throws IOException{ return (int)nextLong(); }
  }
}

